import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"旅行者斗篷","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/旅行者斗篷.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/旅行者斗篷.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/旅行者斗篷.md"};function p(_,r,l,b,i,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"旅行者斗篷",tabindex:"-1"},[s("旅行者斗篷 "),e("a",{class:"header-anchor",href:"#旅行者斗篷","aria-label":'Permalink to "旅行者斗篷"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="旅行者斗篷-1" tabindex="-1">旅行者斗篷 <a class="header-anchor" href="#旅行者斗篷-1" aria-label="Permalink to &quot;旅行者斗篷&quot;">​</a></h1><p>旅行者斗篷<br> 本质：魔幻<br> 价格：D+750<br> 占据肩部-斗篷位<br> —— 旅行者斗篷，守护您的每一步。<br> 每一位冒险者都值得拥，不仅实用，更是经济实惠的选择。<br> 艾洛斯大师亲传工艺，品质保证，让你的旅途更加精彩。<br>  现在就购买，开启你的冒险之旅！</p><p>外观描述：<br> 常规状态下，旅行者斗篷由一种看似普通却异常耐用的深绿色布料制成，其表面细腻光滑，边缘镶有精致的银色丝线。斗篷的内部缝制有两竖排共十个口袋，每一个口袋都有一个包含缩小术的魔法符文。</p><p>【旅行背包】：告别臃肿负担，轻松携带一切所需。我们的魔法口袋设计，容量超乎想象！<br> 穿戴者可以整轮动作从口袋中取出或放入物品，就像在使用一个好用的的背包一样。但每个口袋仅可以放入一立方米的物品，无论是长剑刀枪都可以放入这个小小的口袋中，而不对斗篷的体积外形产生任何影响。但放入其中的物品重量并不会消失，正常占据穿戴者的负重。</p><p>【睡眠警戒】：在野外安营扎寨，也能安心入梦。旅行者斗篷的警戒功能，让你在甜美梦乡中也能对四周环境保持警觉，任何风吹草动，即刻唤醒。<br> 旅行者斗篷斗篷相当的耐用，虽然不能抵御攻击，但其上的魔法符文足够免疫日常的磨损。同时穿戴者可在睡眠时用斗篷包裹自身，就如同使用睡袋一般。当使用者如此使用并进入睡眠后，斗篷还将启用温度调节符文和警戒符文。<br> -温度调节符文：使穿戴者在任何恶劣的环境内获得舒适的睡眠。<br> -警戒符文：这个效果需要在入睡前预备，当穿戴者入睡后，以穿戴者为半径10米内，若有全生理属性超过1的生物从外部靠近，斗篷就会发出尖锐声响，使穿戴者立刻惊醒，但准备了这个效果会使你无法正常获得长休息的好处。</p><p>【外形伪装】<br> 融入自然，隐于市井。只需一念之间，斗篷便可变化外形，修改穿戴者容貌，让你在探险中如鱼得水，隐秘行动。<br> 整轮动作使用，持续时间无限。斗篷可以变形成任意一件足够朴素大众的衣物，使穿戴者在不同的环境内，最少不会因奇装异服而备受瞩目，同时，这一变形能力也可作用穿戴者本身，允许穿戴者改变肤色发色，去除纹身，稍稍变的更壮或更瘦，但无法影响体积或用这一能力模仿任何生物外貌，这是D级变形效果的能力。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
